<template>
	<component
		:is="as"
		class="relative inline-block overflow-hidden !bg-transparent !border-none !rounded-[20px]" :class="[customClass]"
		v-bind="restAttrs"
		:style="componentStyle"
	>
		<div
			class="absolute w-[300%] h-[50%] opacity-70 bottom-[-11px] right-[-250%] rounded-full animate-star-movement-bottom z-0"
			:style="{
  background: `radial-gradient(circle, ${color}, transparent 10%)`,
  animationDuration: speed
}"
		/>

		<div
			class="absolute w-[300%] h-[50%] opacity-70 top-[-10px] left-[-250%] rounded-full animate-star-movement-top z-0"
			:style="{
  background: `radial-gradient(circle, ${color}, transparent 10%)`,
  animationDuration: speed
}"
		/>

		<div
			class="relative z-10 border border-[#333] bg-[#0b0b0b] text-white text-[16px] text-center px-[64px] py-[24px] rounded-[20px]"
		>
			<slot />
		</div>
	</component>
</template>

<script setup>
import { computed, defineProps, useAttrs } from "vue";
const props = defineProps({
  as: { type: String, required: false, default: "button" },
  customClass: { type: String, required: false, default: "" },
  color: { type: String, required: false, default: "white" },
  speed: { type: String, required: false, default: "6s" },
  thickness: { type: Number, required: false, default: 1 }
});
const restAttrs = useAttrs();
const componentStyle = computed(() => {
  const base = {
    padding: `${props.thickness}px 0`
  };
  const userStyle = restAttrs.style || {};
  return { ...base, ...userStyle };
});
</script>

<style scoped>
@keyframes star-movement-bottom{0%{opacity:1;transform:translate(0)}to{opacity:0;transform:translate(-100%)}}@keyframes star-movement-top{0%{opacity:1;transform:translate(0)}to{opacity:0;transform:translate(100%)}}.animate-star-movement-bottom{animation:star-movement-bottom linear infinite alternate}.animate-star-movement-top{animation:star-movement-top linear infinite alternate}
</style>
